            align-items: center;
            gap: 6mm;
            line-height: 1.2;
          }
          .details-item {
            display: flex;
            gap: 2mm;
            align-items: baseline;
          }
          .details-label {
            color: #555;
            font-size: 9pt;
            white-space: nowrap;
          }
          .details-value {
            font-weight: 800;
            font-size: 11pt;
            color: #000;
          }
          .no-print-bar {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            background: #1f2937;
            color: white;
            padding: 10px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            z-index: 1000;
          }
          .btn-group {
            display: flex;
            gap: 10px;
          }
          .print-btn {
            background: #2563eb;
            color: white;
            border: none;
            padding: 8px 16px;
