            border: none;
            padding: 8px 16px;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
          }
          .pdf-btn:disabled {
            background: #9ca3af;
            cursor: not-allowed;
          }
          @media print {
            .no-print-bar { display: none; }
