              margin: 0; 
              transform: scale(0.95); 
              transform-origin: top left;
              box-shadow: none;
              page-break-after: always;
            }
          }
        </style>
      </head>
      <body>
        <div class="no-print-bar">
          <span>図面プレビュー: ${storage.size} (${siteName || '現場名未設定'}) - 表示倍率 85%</span>
          <div class="btn-group">
            <button id="pdf-btn" class="pdf-btn">PDF合成保存</button>
            <button class="print-btn" onClick="window.print()">印刷</button>
