            gap: 4mm;
          }
          .details-item {
            display: flex;
            align-items: baseline;
            gap: 1.5mm;
          }
          .details-label {
            color: #666;
            font-size: 8pt;
            white-space: nowrap;
          }
          .details-value {
            font-weight: bold;
            font-size: 10pt;
            color: #000;
            white-space: nowrap;
            line-height: 1.2;
          }
          .no-print-bar {
            position: fixed;
            top: 0;
