              transform-origin: top left;
              box-shadow: none;
              page-break-after: always;
            }
          }
        </style>
      </head>
      <body>
        <div class="no-print-bar">
          <span>図面プレビュー: ${wdText} (${siteName || '現場名未設定'}) - 表示倍率 85%</span>
          <div class="btn-group">
            <button id="pdf-btn" class="pdf-btn">PDF合成保存</button>
            <button class="print-btn" onClick="window.print()">印刷</button>
          </div>
        </div>
        <div class="page-container">
          <div class="background-media">
            ${isPdf 
              ? `<iframe src="${finalUrl}#toolbar=0&navpanes=0&scrollbar=0&view=FitH" class="background-pdf"></iframe>`
              : `<div class="background-image"></div>`
            }
          </div>
          <div class="overlay-header">
            <div class="wd-box">${wdText}</div>
            <div class="details-box">
              <div class="details-row">
                <div class="details-item"><span class="details-label">物件名</span><span class="details-value">${siteName || ''}</span></div>
                <div class="details-item"><span class="details-label">部屋名</span><span class="details-value">${door.roomName || ''}</span></div>
                <div class="details-item"><span class="details-label">種類</span><span class="details-value">${door.type}</span></div>
                <div class="details-item"><span class="details-label">デザイン</span><span class="details-value" style="${getHighlightStyle(isDesignHighlighted)}">${door.design}</span></div>
                <div class="details-item"><span class="details-label">サイズ</span><span class="details-value">${widthHtml}×${heightHtml}</span></div>
              </div>
              <div class="details-row">
                <div class="details-item"><span class="details-label">枠仕様</span><span class="details-value">${door.frameType}${frameOptionHtml}</span></div>
                <div class="details-item"><span class="details-label">吊元</span><span class="details-value">${door.hangingSide}</span></div>
                <div class="details-item"><span class="details-label">扉色</span><span class="details-value" style="${getHighlightStyle(isDoorColorHighlighted)}">${door.doorColor}</span></div>
                <div class="details-item"><span class="details-label">枠色</span><span class="details-value" style="${getHighlightStyle(isFrameColorHighlighted)}">${door.frameColor}</span></div>
                <div class="details-item"><span class="details-label">ハンドル</span><span class="details-value" style="${getHighlightStyle(isHandleColorHighlighted)}">${door.handleColor}</span></div>
              </div>
            </div>
          </div>
        </div>
        <script>
          window.doorData = ${JSON.stringify(pdfData)};
        </script>
        <script type="module">
          import { PDFDocument, rgb } from 'pdf-lib';
          import fontkit from '@pdf-lib/fontkit';

          document.getElementById('pdf-btn').addEventListener('click', async function() {
            const btn = this;
            btn.textContent = '作成中...';
            btn.disabled = true;

            try {
              // 1. Fetch Japanese Font (Error handling added)
              let fontBytes;
              try {
                  const fontUrl = 'https://cdn.jsdelivr.net/npm/@fontsource/noto-sans-jp@5.0.19/files/noto-sans-jp-all-700-normal.woff';
                  const res = await fetch(fontUrl);
                  if (!res.ok) throw new Error('Font status: ' + res.status);
                  fontBytes = await res.arrayBuffer();
              } catch (e) {
                  throw new Error('フォントの取得に失敗しました。\\n' + e.message);
              }

              // 2. Fetch Background (PDF or Image) with improved error handling
              let existingPdfBytes;
              try {
                  // Add timestamp to prevent caching issues
                  const url = window.doorData.finalUrl + (window.doorData.finalUrl.includes('?') ? '&' : '?') + 't=' + new Date().getTime();
                  const res = await fetch(url, { cache: 'no-cache', credentials: 'omit' });
                  if (!res.ok) throw new Error('Background status: ' + res.status);
                  existingPdfBytes = await res.arrayBuffer();
              } catch (e) {
                  let msg = '背景図面の取得に失敗しました。\\n' + e.message;
                  // Hint for Mixed Content or CORS
                  if (window.location.protocol === 'https:' && window.doorData.finalUrl.startsWith('http:')) {
                      msg += '\\n\\n【原因の可能性】\\nセキュリティ保護されたページ(HTTPS)から非保護の画像(HTTP)を取得しようとしてブロックされました。';
                  } else {
                      msg += '\\n\\n【原因の可能性】\\n画像サーバーへのアクセスが制限されている可能性があります(CORS)。';
                  }
                  throw new Error(msg);
              }

              // 3. Load PDF Document
              let pdfDoc;
              let isImage = false;
              const fileType = window.doorData.finalUrl.split('.').pop().toLowerCase();

              if (fileType === 'pdf') {
                pdfDoc = await PDFDocument.load(existingPdfBytes);
              } else {
                pdfDoc = await PDFDocument.create();
                isImage = true;
                const page = pdfDoc.addPage([1190.55, 841.89]); // A3 Landscape size in points (420mm x 297mm)

                let image;
                if (fileType === 'png') {
                  image = await pdfDoc.embedPng(existingPdfBytes);
                } else {
                  image = await pdfDoc.embedJpg(existingPdfBytes);
                }

                // Scale image to fit A3
                page.drawImage(image, {
                  x: 0,
                  y: 0,
                  width: 1190.55,
                  height: 841.89,
                });
              }

              // 4. Register Fontkit
              pdfDoc.registerFontkit(fontkit);
              const customFont = await pdfDoc.embedFont(fontBytes);

              // 5. Draw Text
              const pages = pdfDoc.getPages();
              const page = pages[0];
              const { width, height } = page.getSize();

              // Constants for layout (converted from mm to points, 1mm = 2.8346pt)
              // HTML top: 10mm -> PDF y: height - 10mm
              // HTML left: 27mm
              const pt = (mm) => mm * 2.8346;
              const startX = pt(27);
              const startY = height - pt(10); // Top margin

              // Colors
              const blueColor = rgb(0.11, 0.31, 0.85); // #1d4ed8
              const blackColor = rgb(0, 0, 0);
              const labelColor = rgb(0.4, 0.4, 0.4);

              // Draw Header Box (WD Number)
              page.drawRectangle({
                x: startX,
                y: startY - pt(12),
                width: pt(28),
                height: pt(12),
                borderColor: blueColor,
                borderWidth: 2,
                color: rgb(1, 1, 1),
              });

              // WD Text
              const wdSize = 24;
              const wdWidth = customFont.widthOfTextAtSize(window.doorData.wdText, wdSize);
              page.drawText(window.doorData.wdText, {
                x: startX + (pt(28) - wdWidth) / 2,
                y: startY - pt(9), // Adjust vertical alignment
                size: wdSize,
                font: customFont,
                color: blueColor,
              });

              // Draw Details Box
              const detailBoxX = startX + pt(30); // Gap

              page.drawRectangle({
                x: detailBoxX,
                y: startY - pt(11), // Slightly shifted down relative to WD box in HTML
                width: pt(250), // Approx width
                height: pt(11),
                borderColor: blueColor,
                borderWidth: 1,
                color: rgb(1, 1, 1),
              });

              const row1Y = startY - pt(4.5);
              const row2Y = startY - pt(9);
              const labelSize = 8;
              const valueSize = 10;

              let currentX = detailBoxX + pt(2);

              const upperY = startY - pt(4.5);
              const lowerY = startY - pt(9);

              // Upper Row
              let ux = currentX;
              // Object Name
              page.drawText("物件名", { x: ux, y: upperY, size: labelSize, font: customFont, color: labelColor });
              ux += customFont.widthOfTextAtSize("物件名", labelSize) + pt(1.5);
              page.drawText(window.doorData.siteName, { x: ux, y: upperY, size: valueSize, font: customFont, color: blackColor });
              ux += customFont.widthOfTextAtSize(window.doorData.siteName, valueSize) + pt(4);

              // Room Name
              page.drawText("部屋名", { x: ux, y: upperY, size: labelSize, font: customFont, color: labelColor });
              ux += customFont.widthOfTextAtSize("部屋名", labelSize) + pt(1.5);
              page.drawText(window.doorData.roomName, { x: ux, y: upperY, size: valueSize, font: customFont, color: blackColor });
              ux += customFont.widthOfTextAtSize(window.doorData.roomName, valueSize) + pt(4);

              // Type
              page.drawText("種類", { x: ux, y: upperY, size: labelSize, font: customFont, color: labelColor });
              ux += customFont.widthOfTextAtSize("種類", labelSize) + pt(1.5);
              page.drawText(window.doorData.type, { x: ux, y: upperY, size: valueSize, font: customFont, color: blackColor });
              ux += customFont.widthOfTextAtSize(window.doorData.type, valueSize) + pt(4);

              // Design
              page.drawText("デザイン", { x: ux, y: upperY, size: labelSize, font: customFont, color: labelColor });
              ux += customFont.widthOfTextAtSize("デザイン", labelSize) + pt(1.5);
              page.drawText(window.doorData.design, { x: ux, y: upperY, size: valueSize, font: customFont, color: blackColor });
              ux += customFont.widthOfTextAtSize(window.doorData.design, valueSize) + pt(4);

              // Size
              page.drawText("サイズ", { x: ux, y: upperY, size: labelSize, font: customFont, color: labelColor });
              ux += customFont.widthOfTextAtSize("サイズ", labelSize) + pt(1.5);
              const sizeText = window.doorData.width + "×" + window.doorData.height;
              page.drawText(sizeText, { x: ux, y: upperY, size: valueSize, font: customFont, color: blackColor });

              // Lower Row
              let lx = currentX;
              // Frame Type
              page.drawText("枠仕様", { x: lx, y: lowerY, size: labelSize, font: customFont, color: labelColor });
              lx += customFont.widthOfTextAtSize("枠仕様", labelSize) + pt(1.5);
              page.drawText(window.doorData.frameType, { x: lx, y: lowerY, size: valueSize, font: customFont, color: blackColor });
              lx += customFont.widthOfTextAtSize(window.doorData.frameType, valueSize) + pt(4);

              // Hanging
              page.drawText("吊元", { x: lx, y: lowerY, size: labelSize, font: customFont, color: labelColor });
              lx += customFont.widthOfTextAtSize("吊元", labelSize) + pt(1.5);
              page.drawText(window.doorData.hangingSide, { x: lx, y: lowerY, size: valueSize, font: customFont, color: blackColor });
              lx += customFont.widthOfTextAtSize(window.doorData.hangingSide, valueSize) + pt(4);

              // Door Color
              page.drawText("扉色", { x: lx, y: lowerY, size: labelSize, font: customFont, color: labelColor });
              lx += customFont.widthOfTextAtSize("扉色", labelSize) + pt(1.5);
              page.drawText(window.doorData.doorColor, { x: lx, y: lowerY, size: valueSize, font: customFont, color: blackColor });
              lx += customFont.widthOfTextAtSize(window.doorData.doorColor, valueSize) + pt(4);

              // Frame Color
              page.drawText("枠色", { x: lx, y: lowerY, size: labelSize, font: customFont, color: labelColor });
              lx += customFont.widthOfTextAtSize("枠色", labelSize) + pt(1.5);
              page.drawText(window.doorData.frameColor, { x: lx, y: lowerY, size: valueSize, font: customFont, color: blackColor });
              lx += customFont.widthOfTextAtSize(window.doorData.frameColor, valueSize) + pt(4);

              // Handle
              page.drawText("ハンドル", { x: lx, y: lowerY, size: labelSize, font: customFont, color: labelColor });
              lx += customFont.widthOfTextAtSize("ハンドル", labelSize) + pt(1.5);
              page.drawText(window.doorData.handleColor, { x: lx, y: lowerY, size: valueSize, font: customFont, color: blackColor });


              // 6. Save and Download
              const pdfBytesOut = await pdfDoc.save();
              const blob = new Blob([pdfBytesOut], { type: 'application/pdf' });
              const link = document.createElement('a');
              link.href = URL.createObjectURL(blob);
              link.download = window.doorData.wdText + '_詳細図.pdf';
              link.click();

              btn.textContent = 'PDF合成保存';
              btn.disabled = false;
            } catch (error) {
              console.error(error);
              alert('PDF作成中にエラーが発生しました:\\n' + error.message);
              btn.textContent = 'PDF合成保存';
              btn.disabled = false;
            }
          });
        </script>
      </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  return (
