        <div className="flex items-center justify-center gap-2 whitespace-nowrap">
          <button 
            onClick={(e) => { e.preventDefault(); handleOpenDetails(); }}
            className="bg-blue-600 hover:bg-blue-700 text-white px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 transition-all active:scale-95 shadow-sm whitespace-nowrap"
            title="詳細図面にWD番号を合成して表示・印刷"
          >
            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2v4h10z" />
            </svg>
            詳細図
          </button>
          <button onClick={() => removeDoor(door.id)} className="text-red-500 hover:text-red-700 p-1 transition-colors shrink-0" title="行を削除">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
          </button>
        </div>
      </td>
    </tr>
  );
};

import React, { useState, useEffect } from 'react';
import { EntranceStorage, StorageTypeRecord } from '../types';
import { STORAGE_CATEGORIES, COLORS, DAIWA_PRICES, getStorageDetailPdfUrl } from '../constants';

interface EntranceStorageSectionProps {
  storage: EntranceStorage;
  updateStorage: (updates: Partial<EntranceStorage>) => void;
  siteName: string;
  storageTypes: StorageTypeRecord[];
}

export const EntranceStorageSection: React.FC<EntranceStorageSectionProps> = ({ storage, updateStorage, siteName, storageTypes }) => {
  const initialCategory = storageTypes.find(s => s.id === storage.type)?.category || "なし";
  const [selectedCategory, setSelectedCategory] = useState(initialCategory);
  const [isFillerInfoOpen, setIsFillerInfoOpen] = useState(false);
  const [isDaiwaInfoOpen, setIsDaiwaInfoOpen] = useState(false);
  const [isMirrorInfoOpen, setIsMirrorInfoOpen] = useState(false);

  const filteredTypes = storageTypes.filter(s => s.category === selectedCategory);
  const mirrorIncompatibleCategories = ["一の字タイプ", "二の字タイプ"];

  const handleOpenDetails = () => {
    let finalUrl = '';
    let isPdf = false;

    const record = storageTypes.find(s => s.id === storage.type);

    if (record && record.imageUrl) {
      finalUrl = record.imageUrl;
    } else {
      finalUrl = getStorageDetailPdfUrl(storage.type);
    }

    isPdf = finalUrl.toLowerCase().endsWith('.pdf');

    const pdfData = {
        finalUrl,
        siteName: siteName || '○○様邸',
        category: selectedCategory,
        size: storage.size,
        color: storage.color
    };

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert('ポップアップがブロックされました。ブラウザの設定を確認してください。');
      return;
    }

    const htmlContent = `
      <!DOCTYPE html>
      <html lang="ja">
      <head>
        <meta charset="UTF-8">
        <title>玄関収納詳細図面 - ${storage.size}</title>
        <script type="importmap">
        {
          "imports": {
            "pdf-lib": "https://esm.sh/pdf-lib@^1.17.1",
            "@pdf-lib/fontkit": "https://esm.sh/@pdf-lib/fontkit@1.1.1"
          }
        }
        </script>
        <style>
          @page { size: A3 landscape; margin: 0; }
          body { 
            margin: 0; 
            padding: 0; 
            background: #eee;
            -webkit-print-color-adjust: exact; 
            print-color-adjust: exact; 
            font-family: 'Noto Sans JP', sans-serif;
            overflow-x: hidden;
            overflow-y: auto;
          }
          .page-container {
            width: 420mm;
            height: 297mm;
            position: relative;
            background-color: white;
            margin: 40px auto;
            overflow: hidden;
            transform: scale(0.85);
            transform-origin: top center;
            box-shadow: 0 10px 30px rgba(0,0,0,0.1);
          }
          .background-media {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 1;
          }
          .background-image {
            width: 100%;
            height: 100%;
            background-image: url('${finalUrl}');
            background-size: contain;
            background-repeat: no-repeat;
            background-position: center;
          }
          .background-pdf {
            width: 100%;
            height: 100%;
            border: none;
          }
          .overlay-header {
            position: absolute;
            top: 10mm;
            left: 27mm;
            display: flex;
            align-items: stretch;
            z-index: 100;
            background: white;
            padding: 2mm 5mm;
            border: 2px solid #ea580c;
            border-radius: 6px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.1);
          }
          .id-box {
            padding: 1mm 4mm;
            font-size: 26pt;
            font-weight: 900;
            color: #ea580c; 
            display: flex;
            align-items: center;
            justify-content: center;
            border-right: 2px solid #ea580c;
            margin-right: 4mm;
          }
          .details-box {
            padding: 1mm 2mm;
            display: flex;
            flex-direction: column;
            justify-content: center;
            min-width: 120mm;
          }
          .details-row {
            display: flex;
            align-items: center;
            gap: 6mm;
            line-height: 1.2;
          }
          .details-item {
            display: flex;
            gap: 2mm;
            align-items: baseline;
          }
          .details-label {
            color: #555;
            font-size: 9pt;
            white-space: nowrap;
          }
          .details-value {
            font-weight: 800;
            font-size: 11pt;
            color: #000;
          }
          .no-print-bar {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            background: #1f2937;
            color: white;
            padding: 10px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            z-index: 1000;
          }
          .btn-group {
            display: flex;
            gap: 10px;
          }
          .print-btn {
            background: #2563eb;
            color: white;
            border: none;
            padding: 8px 16px;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
          }
          .pdf-btn {
            background: #ea580c;
            color: white;
            border: none;
            padding: 8px 16px;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
          }
          .pdf-btn:disabled {
            background: #9ca3af;
            cursor: not-allowed;
          }
          @media print {
            .no-print-bar { display: none; }
