              margin: 0; 
              transform: scale(0.95); 
              transform-origin: top left;
              box-shadow: none;
              page-break-after: always;
            }
          }
        </style>
      </head>
      <body>
        <div class="no-print-bar">
          <span>図面プレビュー: ${storage.size} (${siteName || '現場名未設定'}) - 表示倍率 85%</span>
          <div class="btn-group">
            <button id="pdf-btn" class="pdf-btn">PDF合成保存</button>
            <button class="print-btn" onClick="window.print()">印刷</button>
          </div>
        </div>
        <div class="page-container">
          <div class="background-media">
             ${isPdf 
              ? `<iframe src="${finalUrl}#toolbar=0&navpanes=0&scrollbar=0&view=FitH" class="background-pdf"></iframe>`
              : `<div class="background-image"></div>`
            }
          </div>
          <div class="overlay-header">
            <div class="id-box">GS</div>
            <div class="details-box">
              <div class="details-row">
                <div class="details-item">
                  <span class="details-label">物件名</span>
                  <span class="details-value">${siteName || '○○様邸'}</span>
                </div>
                <div class="details-item">
                  <span class="details-label">種類</span>
                  <span class="details-value">${selectedCategory}</span>
                </div>
              </div>
              <div class="details-row" style="margin-top: 1mm;">
                <div class="details-item">
                  <span class="details-label">仕様</span>
                  <span class="details-value">${storage.size}</span>
                </div>
                <div class="details-item">
                  <span class="details-label">カラー</span>
                  <span class="details-value">${storage.color}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
        <script>
            window.storageData = ${JSON.stringify(pdfData)};
        </script>
        <script type="module">
          import { PDFDocument, rgb } from 'pdf-lib';
          import fontkit from '@pdf-lib/fontkit';

          document.getElementById('pdf-btn').addEventListener('click', async function() {
            const btn = this;
            btn.textContent = '作成中...';
            btn.disabled = true;

            try {
              // 1. Fetch Japanese Font (Error handling added)
              let fontBytes;
              try {
                  const fontUrl = 'https://cdn.jsdelivr.net/npm/@fontsource/noto-sans-jp@5.0.19/files/noto-sans-jp-all-700-normal.woff';
                  const res = await fetch(fontUrl);
                  if (!res.ok) throw new Error('Font status: ' + res.status);
                  fontBytes = await res.arrayBuffer();
              } catch (e) {
                  throw new Error('フォントの取得に失敗しました。\\n' + e.message);
              }

              // 2. Fetch Background (PDF or Image) with improved error handling
              let existingPdfBytes;
              try {
                  // Add timestamp to prevent caching issues
                  const url = window.storageData.finalUrl + (window.storageData.finalUrl.includes('?') ? '&' : '?') + 't=' + new Date().getTime();
                  const res = await fetch(url, { cache: 'no-cache', credentials: 'omit' });
                  if (!res.ok) throw new Error('Background status: ' + res.status);
                  existingPdfBytes = await res.arrayBuffer();
              } catch (e) {
                  let msg = '背景図面の取得に失敗しました。\\n' + e.message;
                  // Hint for Mixed Content or CORS
                  if (window.location.protocol === 'https:' && window.storageData.finalUrl.startsWith('http:')) {
                      msg += '\\n\\n【原因の可能性】\\nセキュリティ保護されたページ(HTTPS)から非保護の画像(HTTP)を取得しようとしてブロックされました。';
                  } else {
                      msg += '\\n\\n【原因の可能性】\\n画像サーバーへのアクセスが制限されている可能性があります(CORS)。';
                  }
                  throw new Error(msg);
              }

              // 3. Load PDF
              let pdfDoc;
              let isImage = false;
              const fileType = window.storageData.finalUrl.split('.').pop().toLowerCase();

              if (fileType === 'pdf') {
                pdfDoc = await PDFDocument.load(existingPdfBytes);
              } else {
                pdfDoc = await PDFDocument.create();
                isImage = true;
                const page = pdfDoc.addPage([1190.55, 841.89]); // A3
                let image;
                if (fileType === 'png') image = await pdfDoc.embedPng(existingPdfBytes);
                else image = await pdfDoc.embedJpg(existingPdfBytes);

                page.drawImage(image, { x: 0, y: 0, width: 1190.55, height: 841.89 });
              }

              // 4. Register Font
              pdfDoc.registerFontkit(fontkit);
              const customFont = await pdfDoc.embedFont(fontBytes);

              // 5. Draw Text
              const pages = pdfDoc.getPages();
              const page = pages[0];
              const { width, height } = page.getSize();
              const pt = (mm) => mm * 2.8346;
              const startX = pt(27);
              const startY = height - pt(10); // Top margin

              // Colors
              const orangeColor = rgb(0.91, 0.34, 0.04); // #ea580c
              const blackColor = rgb(0, 0, 0);
              const labelColor = rgb(0.33, 0.33, 0.33);

              // Draw Outer Box
              page.drawRectangle({
                x: startX,
                y: startY - pt(15),
                width: pt(160), // Approx width
                height: pt(15),
                borderColor: orangeColor,
                borderWidth: 2,
                color: rgb(1, 1, 1),
              });

              // ID Box Line
              page.drawLine({
                start: { x: startX + pt(15), y: startY },
                end: { x: startX + pt(15), y: startY - pt(15) },
                color: orangeColor,
                thickness: 2,
              });

              // GS Text
              page.drawText("GS", {
                x: startX + pt(1.5),
                y: startY - pt(11),
                size: 26,
                font: customFont,
                color: orangeColor,
              });

              // Details
              const detailX = startX + pt(19);
              const row1Y = startY - pt(5.5);
              const row2Y = startY - pt(11.5);
              const labelSize = 9;
              const valueSize = 11;

              let cx = detailX;
              // Object Name
              page.drawText("物件名", { x: cx, y: row1Y, size: labelSize, font: customFont, color: labelColor });
              cx += customFont.widthOfTextAtSize("物件名", labelSize) + pt(2);
              page.drawText(window.storageData.siteName, { x: cx, y: row1Y, size: valueSize, font: customFont, color: blackColor });
              cx += customFont.widthOfTextAtSize(window.storageData.siteName, valueSize) + pt(6);

              // Category
              page.drawText("種類", { x: cx, y: row1Y, size: labelSize, font: customFont, color: labelColor });
              cx += customFont.widthOfTextAtSize("種類", labelSize) + pt(2);
              page.drawText(window.storageData.category, { x: cx, y: row1Y, size: valueSize, font: customFont, color: blackColor });

              cx = detailX;
              // Size
              page.drawText("仕様", { x: cx, y: row2Y, size: labelSize, font: customFont, color: labelColor });
              cx += customFont.widthOfTextAtSize("仕様", labelSize) + pt(2);
              page.drawText(window.storageData.size, { x: cx, y: row2Y, size: valueSize, font: customFont, color: blackColor });
              cx += customFont.widthOfTextAtSize(window.storageData.size, valueSize) + pt(6);

              // Color
              page.drawText("カラー", { x: cx, y: row2Y, size: labelSize, font: customFont, color: labelColor });
              cx += customFont.widthOfTextAtSize("カラー", labelSize) + pt(2);
              page.drawText(window.storageData.color, { x: cx, y: row2Y, size: valueSize, font: customFont, color: blackColor });

              // 6. Download
              const pdfBytesOut = await pdfDoc.save();
              const blob = new Blob([pdfBytesOut], { type: 'application/pdf' });
              const link = document.createElement('a');
              link.href = URL.createObjectURL(blob);
              link.download = 'GS_詳細図.pdf';
              link.click();

              btn.textContent = 'PDF合成保存';
              btn.disabled = false;
            } catch (error) {
              console.error(error);
              alert('PDF作成中にエラーが発生しました:\\n' + error.message);
              btn.textContent = 'PDF合成保存';
              btn.disabled = false;
            }
          });
        </script>
      </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newCategory = e.target.value;
    setSelectedCategory(newCategory);

    if (newCategory === "なし") {
      updateStorage({
        type: "NONE",
        size: "なし",
        basePrice: 0,
        baseRing: "なし",
        baseRingPrice: 0,
        mirror: "なし",
        mirrorPrice: 0,
        fillerPrice: 0,
        fillerCount: 0
      });
    } else {
      const firstInCat = storageTypes.find(s => s.category === newCategory);
      if (firstInCat) {
        const updates: Partial<EntranceStorage> = {
          type: firstInCat.id,
          size: firstInCat.name,
          basePrice: firstInCat.price,
          baseRingPrice: storage.baseRing !== "なし" ? (DAIWA_PRICES[firstInCat.width] || 0) : 0
        };

        if (mirrorIncompatibleCategories.includes(newCategory)) {
          updates.mirror = "なし";
          updates.mirrorPrice = 0;
        }

        updateStorage(updates);
      }
    }
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selected = storageTypes.find(s => s.id === e.target.value);
    if (selected) {
      updateStorage({
        type: selected.id,
        size: selected.name,
        basePrice: selected.price,
        baseRingPrice: storage.baseRing !== "なし" ? (DAIWA_PRICES[selected.width] || 0) : 0
      });
    }
  };

  const handleBaseRingToggle = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const hasBaseRing = e.target.value === "あり";
    const selected = storageTypes.find(s => s.id === storage.type);
    const width = selected?.width || 0;

    updateStorage({
      baseRing: e.target.value,
      baseRingPrice: hasBaseRing ? (DAIWA_PRICES[width] || 0) : 0
    });
  };

  const isNone = storage.type === 'NONE';
  const isMirrorDisabled = isNone || mirrorIncompatibleCategories.includes(selectedCategory);

  const total = isNone ? 0 : (storage.basePrice + storage.baseRingPrice + (storage.fillerPrice * storage.fillerCount) + storage.mirrorPrice);

  const Modal = ({ isOpen, onClose, title, imageUrl, children }: { isOpen: boolean, onClose: () => void, title: string, imageUrl?: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
      <div 
        className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 no-print"
        onClick={onClose}
      >
        <div 
          className="bg-white p-6 rounded-2xl shadow-2xl max-w-md w-full animate-in zoom-in duration-200 overflow-hidden"
          onClick={(e) => e.stopPropagation()}
        >
          <div className="flex justify-between items-center mb-4">
            <h4 className="text-lg font-bold text-gray-800">{title}</h4>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          {imageUrl && <img src={imageUrl} alt={title} className="w-full h-auto rounded-lg mb-4 max-h-[60vh] object-contain" />}
          {children}
          <div className="mt-6 flex justify-end">
            <button 
              onClick={onClose}
              className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-2 rounded-lg text-sm font-bold transition-colors"
            >
              閉じる
            </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className={`bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-6 print-break-inside-avoid ${isNone ? 'opacity-70' : ''}`}>
      <Modal isOpen={isFillerInfoOpen} onClose={() => setIsFillerInfoOpen(false)} title="フィラー（幕板）について">
        <p className="text-gray-600 leading-relaxed text-sm mb-4">
          「フィラー（幕板）」とは、玄関収納と壁の間に取り付ける隙間を埋めるための板。扉の開閉が完全に行なわれるようにする役割もあります。
        </p>
        <div className="bg-blue-50 p-5 rounded-xl border border-blue-100 space-y-4 text-xs text-gray-700">
          <div>
            <p className="font-bold text-blue-900 border-b border-blue-200 pb-1 mb-2">フィラーセット サイズ 60×18×長さ</p>
          </div>
          <div>
            <p className="font-bold text-gray-900 flex justify-between">
              <span>セパレートタイプセット</span>
              <span className="text-blue-700 font-bold">2,000円</span>
            </p>
            <p className="mt-1">長さ＝900㎜/1本　長さ400㎜/2本</p>
          </div>
          <div className="pt-2">
            <p className="font-bold text-gray-900 flex justify-between">
              <span>トールタイプセット</span>
              <span className="text-blue-700 font-bold">2,000円</span>
            </p>
            <p className="mt-1">長さ＝2100㎜/１本　長さ＝400㎜/2本</p>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isDaiwaInfoOpen} onClose={() => setIsDaiwaInfoOpen(false)} title="台輪について" imageUrl="http://25663cc9bda9549d.main.jp/aistudio/door/daiwa.jpg">
        <p className="text-xs text-gray-500">玄関収納本体を支える下部パーツです。</p>
      </Modal>

      <Modal isOpen={isMirrorInfoOpen} onClose={() => setIsMirrorInfoOpen(false)} title="ミラーについて" imageUrl="http://25663cc9bda9549d.main.jp/aistudio/door/mirror.JPG">
        <p className="text-xs text-gray-500">扉に設置される全身鏡オプションです。</p>
      </Modal>

      <div className="flex justify-between items-center mb-4 border-l-4 border-orange-500 pl-3">
        <h3 className="text-xl font-bold text-gray-800">玄関収納</h3>
        <button
          onClick={(e) => {
            e.preventDefault();
            handleOpenDetails();
          }}
          disabled={isNone}
          className={`no-print px-4 py-1.5 rounded-lg text-xs font-bold transition-all shadow-md active:scale-95 whitespace-nowrap flex items-center gap-2 ${isNone ? 'bg-gray-100 text-gray-300 cursor-not-allowed shadow-none border border-gray-100' : 'bg-blue-600 hover:bg-blue-700 text-white'}`}
        >
